"use client";

import { useState, useEffect } from "react";
import { useRouter, usePathname } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { cn } from "@/lib/utils";
import type React from "react";
import type { LucideIcon } from "lucide-react";
import {
  LayoutDashboard,
  CalendarDays,
  Users,
  BrainCircuit,
  Send,
  Wallet,
  Settings2,
  Menu,
  X,
  LogOut,
} from "lucide-react";

interface TherapistProfile {
  id: string;
  name: string;
  crp: string;
  slug: string;
  onboarding_completed: boolean;
  ai_model: string | null;
  telegram_bot_username: string | null;
  openrouter_key_hash?: string | null;
}

interface User {
  id: string;
  email?: string;
}

interface NavItem {
  id: string;
  label: string;
  icon: LucideIcon;
  path: string;
}

const NAV: NavItem[] = [
  { id: "dashboard", label: "Dashboard", icon: LayoutDashboard, path: "/dashboard" },
  { id: "agenda", label: "Agenda", icon: CalendarDays, path: "/dashboard/agenda" },
  { id: "pacientes", label: "Pacientes", icon: Users, path: "/dashboard/pacientes" },
  { id: "ia", label: "IA Clínica", icon: BrainCircuit, path: "/dashboard/ia" },
  { id: "telegram", label: "Telegram", icon: Send, path: "/dashboard/telegram" },
  { id: "financeiro", label: "Financeiro", icon: Wallet, path: "/dashboard/financeiro" },
  { id: "configuracoes", label: "Configurações", icon: Settings2, path: "/dashboard/configuracoes" },
];

function initials(name: string): string {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

export function DashboardShell({
  therapist,
  user,
  children,
}: {
  therapist: TherapistProfile | null;
  user: User;
  children: React.ReactNode;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const supabase = createClient();
  const [signingOut, setSigningOut] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  useEffect(() => {
    if (therapist && !therapist.onboarding_completed && !pathname.includes("onboarding")) {
      router.push("/dashboard/onboarding");
    }
  }, [therapist, pathname, router]);

  useEffect(() => {
    setSidebarOpen(false);
  }, [pathname]);

  const handleSignOut = async () => {
    setSigningOut(true);
    await supabase.auth.signOut();
    router.push("/auth/login");
  };

  const isActive = (path: string) => pathname === path;

  return (
    <div className="relative flex h-screen w-full overflow-hidden bg-[var(--color-bg-base)]">
      <div className="pointer-events-none fixed inset-0 z-0 overflow-hidden">
        <div className="absolute -left-[10%] -top-[20%] h-[50%] w-[50%] rounded-full bg-[var(--color-brand)]/12 blur-[140px]" />
        <div className="absolute -bottom-[22%] -right-[12%] h-[62%] w-[62%] rounded-full bg-sky-400/8 blur-[170px]" />
        <div className="noise-overlay absolute inset-0 opacity-[0.018] mix-blend-overlay" />
      </div>

      <header className="absolute left-0 right-0 top-0 z-30 flex h-16 w-full items-center justify-between border-b border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)]/85 px-4 backdrop-blur-xl lg:hidden">
        <button
          type="button"
          onClick={() => setSidebarOpen((v) => !v)}
          className="inline-flex h-10 w-10 items-center justify-center rounded-xl border border-[var(--color-border-subtle)] bg-[var(--color-surface)] text-[var(--color-text-primary)]"
          aria-label="Abrir menu"
        >
          {sidebarOpen ? <X size={18} /> : <Menu size={18} />}
        </button>
        <div className="flex items-center gap-2">
          <span className="font-[family-name:var(--font-display)] text-2xl font-light text-[var(--color-brand)]">Ψ</span>
          <span className="font-[family-name:var(--font-display)] text-xl font-light text-[var(--color-text-primary)]">Psique</span>
        </div>
        <div className="w-10" />
      </header>

      <div
        className={cn(
          "absolute inset-y-0 left-0 z-20 w-72 shrink-0 border-r border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)]/90 backdrop-blur-xl transition-transform duration-300 lg:relative lg:translate-x-0",
          sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"
        )}
      >
        <aside className="flex h-full flex-col">
          <div className="border-b border-[var(--color-border-subtle)] px-6 py-6">
            <div className="flex items-center gap-3">
              <div className="font-[family-name:var(--font-display)] text-4xl font-light leading-none text-[var(--color-brand)]">Ψ</div>
              <div>
                <div className="font-[family-name:var(--font-display)] text-[24px] font-light text-[var(--color-text-primary)]">Psique</div>
                <div className="mt-0.5 text-[10px] font-semibold uppercase tracking-[0.22em] text-[var(--color-brand)]">Painel Clínico</div>
              </div>
            </div>
          </div>

          <div className="border-b border-[var(--color-border-subtle)] px-5 py-5">
            <div className="flex items-center gap-3">
              <div className="relative flex h-11 w-11 shrink-0 items-center justify-center overflow-hidden rounded-2xl border border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-sm font-semibold text-[var(--color-brand)]">
                <div className="pointer-events-none absolute inset-0 bg-gradient-to-tr from-[var(--color-brand)]/20 to-transparent" />
                <span className="relative z-10">{therapist ? initials(therapist.name) : "?"}</span>
              </div>
              <div className="min-w-0">
                <div className="truncate text-[14px] font-semibold text-[var(--color-text-primary)]">{therapist?.name ?? user.email}</div>
                <div className="truncate text-[12px] text-[var(--color-text-muted)]">{therapist?.crp ? `CRP ${therapist.crp}` : "Carregando..."}</div>
              </div>
            </div>
          </div>

          <nav className="custom-scrollbar flex flex-1 flex-col gap-1 overflow-y-auto px-3 py-4">
            {NAV.map((item) => {
              const Icon = item.icon;
              const active = isActive(item.path);
              return (
                <button
                  key={item.id}
                  onClick={() => router.push(item.path)}
                  aria-label={item.label}
                  aria-current={active ? "page" : undefined}
                  className={cn(
                    "group flex w-full items-center gap-3 rounded-xl px-4 py-3 text-left text-[14px] font-medium transition-all duration-300",
                    active
                      ? "border border-[var(--color-brand)]/35 bg-[linear-gradient(90deg,rgba(82,183,136,0.26),rgba(82,183,136,0.05))] text-[var(--color-brand)] shadow-[0_8px_22px_rgba(82,183,136,0.2)]"
                      : "text-[var(--color-text-secondary)] hover:border hover:border-[var(--color-border-strong)] hover:bg-[var(--color-surface-hover)] hover:text-[var(--color-text-primary)]"
                  )}
                >
                  <Icon size={17} className={cn("shrink-0 transition-colors", active ? "text-[var(--color-brand)]" : "text-[var(--color-text-muted)] group-hover:text-[var(--color-text-primary)]")} />
                  {item.label}
                </button>
              );
            })}
          </nav>

          <div className="mx-4 mb-3 rounded-2xl border border-[var(--color-border-strong)] bg-[var(--color-surface)] p-3">
            <div className="mb-1 flex items-center gap-2 text-[12px] font-semibold text-sky-300">
              <BrainCircuit size={14} /> OpenRouter IA
            </div>
            <div className="flex items-center justify-between text-[11px] text-[var(--color-text-muted)]">
              <span className="truncate max-w-[130px]">{therapist?.ai_model?.split("/")[1]?.split("-").slice(0, 2).join(" ") ?? "Claude Sonnet"}</span>
              <span className={cn("inline-flex items-center gap-1.5 font-semibold", therapist?.openrouter_key_hash ? "text-[var(--color-brand)]" : "text-[var(--color-text-muted)]")}>
                <span className={cn("inline-block h-1.5 w-1.5 rounded-full", therapist?.openrouter_key_hash ? "bg-[var(--color-brand)] shadow-[0_0_10px_var(--color-brand)]" : "bg-[var(--color-text-muted)]")} />
                {therapist?.openrouter_key_hash ? "Próprio" : "Plataforma"}
              </span>
            </div>
          </div>

          {therapist?.telegram_bot_username && (
            <div className="mx-4 mb-4 rounded-2xl border border-sky-400/20 bg-sky-400/10 p-3">
              <div className="mb-1 inline-flex items-center gap-2 text-[12px] font-semibold text-sky-300">
                <Send size={13} /> Telegram
              </div>
              <div className="truncate text-[11px] text-sky-200">@{therapist.telegram_bot_username}</div>
            </div>
          )}

          <div className="px-4 pb-6 pt-2">
            <button
              onClick={handleSignOut}
              disabled={signingOut}
              className="flex w-full items-center gap-2 rounded-xl px-4 py-2.5 text-[13px] font-medium text-[var(--color-text-muted)] transition-all duration-300 hover:bg-[var(--color-surface-hover)] hover:text-[var(--color-text-primary)]"
            >
              {signingOut ? (
                <span className="inline-block h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
              ) : (
                <LogOut size={15} />
              )}
              {signingOut ? "Saindo..." : "Sair da conta"}
            </button>
          </div>
        </aside>
      </div>

      {sidebarOpen && (
        <button
          type="button"
          className="absolute inset-0 z-10 bg-black/50 lg:hidden"
          onClick={() => setSidebarOpen(false)}
          aria-label="Fechar menu"
        />
      )}

      <main className="custom-scrollbar relative z-10 flex min-w-0 flex-1 flex-col overflow-y-auto pt-16 lg:pt-0">
        {children}
      </main>
    </div>
  );
}
